import React, { useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Container,
  Box,
  Typography,
  Button,
  CircularProgress,
  Alert,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
} from '@mui/material';
import { Add as AddIcon } from '@mui/icons-material';
import { AuthContext } from '../context/AuthContext';
import api from '../api';
import KanbanBoard from '../components/KanbanBoard';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const [tasks, setTasks] = useState([]);
  const [progressions, setProgressions] = useState([]);
  const [selectedProgressionId, setSelectedProgressionId] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [openDialog, setOpenDialog] = useState(false);
  const [progressionName, setProgressionName] = useState('');
  const [progressionDescription, setProgressionDescription] = useState('');

  const fetchProgressions = async () => {
    try {
      const res = await api.get('/task-progressions');
      const body = res.data;
      const list = Array.isArray(body) ? body : (body.progressions ?? body.data ?? []);
      setProgressions(list || []);
    } catch (err) {
      console.error('Failed to load progressions', err);
    }
  };

  const fetchTasks = async () => {
    setLoading(true);
    try {
      const res = await api.get('/tasks');
      const body = res.data;
      const list = Array.isArray(body) ? body : (body.tasks ?? body.data ?? []);
      setTasks(list || []);
      setError('');
    } catch (err) {
      console.error('Failed to load tasks', err);
      setError('Failed to load tasks');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProgressions();
    fetchTasks();
  }, []);

  const handleMoveTask = async (taskId, info) => {
    try {
      const column = info.column;
      // if selectedProgressionId is set and column is numeric => treat as progression step id
      const isNumeric = String(column).match(/^[0-9]+$/);
      const payload = isNumeric ? { task_progression_step_id: column } : { status: column };
      await api.patch(`/tasks/${taskId}/status`, payload);
      fetchTasks();
    } catch (err) {
      console.error('Failed to move task', err);
    }
  };

  const handleCreateProgression = async () => {
    if (!progressionName.trim()) {
      alert('Please enter a progression name');
      return;
    }
    try {
      await api.post('/task-progressions', {
        name: progressionName,
        description: progressionDescription,
      });
      setProgressionName('');
      setProgressionDescription('');
      setOpenDialog(false);
      await fetchProgressions();
    } catch (err) {
      console.error('Failed to create progression', err);
      alert('Failed to create progression: ' + (err.response?.data?.message || err.message));
    }
  };

  // derive columns based on selected progression or fallback to legacy
  const getColumns = () => {
    if (selectedProgressionId) {
      const prog = progressions.find((p) => String(p.id) === String(selectedProgressionId));
      if (prog && prog.steps && prog.steps.length) return prog.steps.map((s) => ({ id: s.id, name: s.name }));
    }

    // fallback: if tasks include progression_steps, use first task's progression_steps
    const firstWith = tasks.find((t) => (t.progression_steps || []).length);
    if (firstWith) return firstWith.progression_steps.map((s) => ({ id: s.id, name: s.name }));

    return [
      { id: null, name: 'To Do', key: 'pending' },
      { id: null, name: 'In Progress', key: 'in_progress' },
      { id: null, name: 'Done', key: 'completed' },
    ];
  };

  const getTasksByColumn = () => {
    const map = {};
    const cols = getColumns();

    // if progression columns (have id not null)
    if (cols && cols.length && cols[0].id != null) {
      cols.forEach((c) => (map[c.id] = []));
      tasks.forEach((task) => {
        const key = task.progression_step?.id ?? null;
        if (map[key]) map[key].push(task);
        else map[cols[0].id].push(task);
      });
      return map;
    }

    // legacy mapping by status
    map['pending'] = tasks.filter((t) => t.status === 'pending');
    map['in_progress'] = tasks.filter((t) => t.status === 'in_progress');
    map['completed'] = tasks.filter((t) => t.status === 'completed');
    return map;
  };

  return (
    <Box sx={{ backgroundColor: '#F8FAFC', minHeight: 'calc(100vh - 64px)', py: 4 }}>
      <Container maxWidth="lg">
        <Box sx={{ mb: 4, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Box>
            <Typography variant="h4" sx={{ fontWeight: 700, mb: 1 }}>
              Task Management
            </Typography>
            <Typography variant="body2" sx={{ color: '#64748B' }}>
              Manage and assign tasks to your team
            </Typography>
          </Box>

          <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
            <FormControl size="small" sx={{ minWidth: 240 }}>
              <InputLabel id="progression-select-label">Board Progression</InputLabel>
              <Select
                labelId="progression-select-label"
                value={selectedProgressionId || ''}
                label="Board Progression"
                onChange={(e) => setSelectedProgressionId(e.target.value || null)}
              >
                <MenuItem value="">Default</MenuItem>
                {progressions.map((p) => (
                  <MenuItem key={p.id} value={String(p.id)}>
                    {p.name}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>

            <Button variant="outlined" onClick={() => setOpenDialog(true)} startIcon={<AddIcon />}>
              New Progression
            </Button>

            <Button variant="contained" startIcon={<AddIcon />} onClick={() => navigate('/admin/create-task')}>
              Create Task
            </Button>
          </Box>
        </Box>

        {error && <Alert severity="error" sx={{ mb: 3 }}>{error}</Alert>}

        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 6 }}>
            <CircularProgress />
          </Box>
        ) : (
          <Box>
            <KanbanBoard
              columns={getColumns()}
              tasksByColumn={getTasksByColumn()}
              currentUser={user}
              canDragTask={() => true}
              onMoveTask={handleMoveTask}
            />
          </Box>
        )}

        <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="sm" fullWidth>
          <DialogTitle>Create New Progression</DialogTitle>
          <DialogContent sx={{ pt: 3 }}>
            <TextField
              autoFocus
              fullWidth
              label="Progression Name"
              placeholder="e.g., Bug Fix, QA Testing"
              value={progressionName}
              onChange={(e) => setProgressionName(e.target.value)}
              variant="outlined"
              sx={{ mb: 2 }}
            />
            <TextField
              fullWidth
              label="Description (Optional)"
              placeholder="Add a description for this progression..."
              value={progressionDescription}
              onChange={(e) => setProgressionDescription(e.target.value)}
              variant="outlined"
              multiline
              rows={3}
            />
          </DialogContent>
          <DialogActions sx={{ p: 2 }}>
            <Button onClick={() => setOpenDialog(false)} variant="text">
              Cancel
            </Button>
            <Button onClick={handleCreateProgression} variant="contained">
              Create
            </Button>
          </DialogActions>
        </Dialog>
      </Container>
    </Box>
  );
}
